/**
 * DataTable Component
 * A reusable React TypeScript component for fetching and displaying API data in a table
 *
 * Features:
 * - Generic type support for flexible data structures
 * - Loading, error, and empty states
 * - CSS-in-JS styling with theme support
 * - Configurable column definitions
 */

import React, { useState, useEffect, useCallback } from 'react';

// =============================================================================
// TYPE DEFINITIONS
// =============================================================================

/**
 * Generic data item - represents any object with string keys and unknown values
 */
export type DataItem = Record<string, unknown>;

/**
 * Column configuration for the table
 * @template T - The type of data items in the table
 */
export interface ColumnConfig<T extends DataItem> {
  /** The key of the property to display from the data item */
  key: keyof T;
  /** Optional custom header label (defaults to key as string) */
  header?: string;
  /** Optional custom render function for cell content */
  render?: (value: unknown, item: T) => React.ReactNode;
  /** Optional custom styling for the column */
  style?: React.CSSProperties;
}

/**
 * Props for the DataTable component
 * @template T - The type of data items in the table
 */
export interface DataTableProps<T extends DataItem = DataItem> {
  /** The API URL to fetch data from */
  apiUrl: string;
  /** Column definitions for the table */
  columns: ColumnConfig<T>[];
  /** Optional fetch options (headers, method, etc.) */
  fetchOptions?: RequestInit;
  /** Optional callback to transform raw API response data */
  transformData?: (data: unknown) => T[];
  /** Optional polling interval in milliseconds (0 to disable) */
  pollInterval?: number;
  /** Optional custom empty state message */
  emptyMessage?: string;
  /** Optional custom error message prefix */
  errorMessagePrefix?: string;
  /** Optional className for styling */
  className?: string;
}

/**
 * Fetch state for managing async data loading
 * @template T - The type of data items
 */
interface FetchState<T> {
  /** The loaded data or null if not yet loaded */
  data: T[] | null;
  /** Loading indicator */
  loading: boolean;
  /** Error message or null if no error */
  error: string | null;
}

// =============================================================================
// STYLES
// =============================================================================

