  /** Optional custom header label (defaults to key as string) */
  header?: string;
  /** Optional custom render function for cell content */
  render?: (value: unknown, item: T) => React.ReactNode;
}

/** Props for the DataTable component */
export interface DataTableProps<T extends DataItem = DataItem> {
  /** The API URL to fetch data from */
  apiUrl: string;
  /** Column definitions for the table */
  columns: ColumnConfig<T>[];
  /** Optional fetch options */
  fetchOptions?: RequestInit;
  /** Optional transform function for raw API data */
  transformData?: (data: unknown) => T[];
  /** Optional custom empty state message */
  emptyMessage?: string;
}

/** Fetch state for managing async data loading */
interface FetchState<T> {
  data: T[] | null;
  loading: boolean;
  error: string | null;
}

